// Parse Director MCP Instructions for Multi-Agent System
const directorResponse = $json;
const systemContext = $('Initialize Multi-Agent Context').first().json.systemContext;

// Extract instruction data
const instructionData = directorResponse.data;

if (!instructionData || !instructionData.instruction) {
  return [{
    instructionText: "Error: No valid instructions received from Director MCP Server",
    error: true,
    task_id: "error_task",
    agentType: "notion"
  }];
}

// Build comprehensive instruction text for the target agent
const instruction = instructionData.instruction;
let instructionText = '';

// Add task header with multi-agent context
instructionText += `# MULTI-AGENT SYSTEM TASK: ${instruction.task_type?.toUpperCase() || 'IDEA_PROCESSING'}\n\n`;

// Add system context
instructionText += `## SYSTEM CONTEXT\n`;
instructionText += `- Session ID: ${systemContext.sessionId}\n`;
instructionText += `- Workflow Type: ${systemContext.workflowType}\n`;
instructionText += `- Current Phase: ${systemContext.currentPhase}\n`;
instructionText += `- Available Agents: ${systemContext.agentsAvailable.join(', ')}\n\n`;

// Add objective
if (instruction.objective) {
  instructionText += `## PRIMARY OBJECTIVE\n${instruction.objective}\n\n`;
}

// Add task parameters
if (instruction.parameters) {
  instructionText += `## TASK PARAMETERS\n`;
  Object.entries(instruction.parameters).forEach(([key, value]) => {
    instructionText += `- ${key}: ${value}\n`;
  });
  instructionText += '\n';
}

// Add categorization methodology for idea processing
if (instructionData.categorization_methodology) {
  instructionText += `## MULTI-IDEA CATEGORIZATION METHODOLOGY\n`;

  if (instructionData.categorization_methodology.multi_idea_parsing_rules) {
    instructionText += `### PARSING RULES:\n`;
    instructionData.categorization_methodology.multi_idea_parsing_rules.forEach(rule => {
      instructionText += `- ${rule}\n`;
    });
    instructionText += '\n';
  }

  if (instructionData.categorization_methodology.database_routing_criteria) {
    instructionText += `### DATABASE ROUTING CRITERIA:\n`;
    Object.entries(instructionData.categorization_methodology.database_routing_criteria).forEach(([key, criteria]) => {
      instructionText += `**${key.toUpperCase()}:**\n`;
      if (criteria.description) instructionText += `- Description: ${criteria.description}\n`;
      if (criteria.keywords) instructionText += `- Keywords: ${criteria.keywords.join(', ')}\n`;
      if (criteria.criteria) instructionText += `- Criteria: ${criteria.criteria}\n`;
      instructionText += '\n';
    });
  }

  if (instructionData.categorization_methodology.analysis_requirements) {
    instructionText += `### ANALYSIS REQUIREMENTS:\n`;
    Object.entries(instructionData.categorization_methodology.analysis_requirements).forEach(([key, requirement]) => {
      instructionText += `- **${key.replace(/_/g, ' ').toUpperCase()}**: ${requirement}\n`;
    });
    instructionText += '\n';
  }
}

// Add execution requirements
if (instructionData.execution_requirements) {
  instructionText += `## EXECUTION REQUIREMENTS\n`;
  if (instructionData.execution_requirements.required_tools) {
    instructionText += `### REQUIRED TOOLS:\n`;
    instructionData.execution_requirements.required_tools.forEach(tool => {
      instructionText += `- ${tool}\n`;
    });
  }
  if (instructionData.execution_requirements.response_format) {
    instructionText += `### RESPONSE FORMAT:\n${instructionData.execution_requirements.response_format}\n`;
  }
  if (instructionData.execution_requirements.processing_approach) {
    instructionText += `### PROCESSING APPROACH:\n${instructionData.execution_requirements.processing_approach}\n`;
  }
  instructionText += '\n';
}

// Add multi-agent coordination instructions
instructionText += `## MULTI-AGENT COORDINATION\n`;
instructionText += `You are part of a multi-agent system. After completing your task:\n`;
instructionText += `1. Return results in the standardized format\n`;
instructionText += `2. Include execution metadata for the next agent\n`;
instructionText += `3. Set status indicators for workflow coordination\n\n`;

// Add execution steps
instructionText += `## EXECUTION STEPS\n`;
instructionText += `1. **Initialize**: Set up task context and parameters\n`;
instructionText += `2. **Retrieve Data**: Use get_ideas tool with limit=${instruction.parameters?.limit || 5}\n`;
instructionText += `3. **Process**: Apply multi-idea parsing and categorization\n`;
instructionText += `4. **Update**: Mark processed items as 'Done'\n`;
instructionText += `5. **Report**: Return comprehensive results for multi-agent coordination\n\n`;

// Add expected output format
instructionText += `## EXPECTED OUTPUT FORMAT\n`;
instructionText += `Return results as JSON with multi-agent metadata:\n`;
instructionText += `{\n`;
instructionText += `  "agent_id": "${instructionData.agent_id}",\n`;
instructionText += `  "task_id": "${instructionData.task_id}",\n`;
instructionText += `  "phase": "${systemContext.currentPhase}",\n`;
instructionText += `  "timestamp": "ISO timestamp",\n`;
instructionText += `  "execution_time_ms": "execution duration",\n`;
instructionText += `  "results": {\n`;
instructionText += `    "ideas_processed": [array of processed ideas],\n`;
instructionText += `    "operations_completed": [array of operations],\n`;
instructionText += `    "summary": {\n`;
instructionText += `      "total_processed": number,\n`;
instructionText += `      "successful": number,\n`;
instructionText += `      "failed": number,\n`;
instructionText += `      "projects": number,\n`;
instructionText += `      "knowledge": number,\n`;
instructionText += `      "journal": number\n`;
instructionText += `    }\n`;
instructionText += `  },\n`;
instructionText += `  "status": {\n`;
instructionText += `    "success": boolean,\n`;
instructionText += `    "errors": [array of errors],\n`;
instructionText += `    "next_phase": "validation_required|workflow_complete"\n`;
instructionText += `  },\n`;
instructionText += `  "context_updates": {\n`;
instructionText += `    "api_calls": number,\n`;
instructionText += `    "tools_used": [array of tools],\n`;
instructionText += `    "performance_notes": "string"\n`;
instructionText += `  }\n`;
instructionText += `}\n\n`;

instructionText += `**BEGIN MULTI-AGENT EXECUTION NOW**\n`;

// Update system context with agent task
systemContext.currentPhase = 'agent_execution';
systemContext.currentAgent = instructionData.agent_id || 'notion';
systemContext.executionHistory.push({
  iteration: systemContext.iteration,
  timestamp: new Date().toISOString(),
  phase: 'director_instructions_parsed',
  agent: instructionData.agent_id || 'notion',
  task_id: instructionData.task_id
});

return [{
  instructionText,
  task_id: instructionData.task_id,
  agent_id: instructionData.agent_id || 'notion',
  agentType: instructionData.agent_id || 'notion',
  systemContext,
  directorResponse: instructionData,
  mcpIntegration: {
    template_loaded: true,
    instructions_created: true,
    ready_for_execution: true
  }
}];

// Process Multi-Agent Results and Update Context
const agentOutput = $json;
const systemContext = $('Parse MCP Instructions').first().json.systemContext;

// Parse agent output
let agentResults;
try {
  const outputText = agentOutput.output || agentOutput.text || JSON.stringify(agentOutput);
  const jsonMatch = outputText.match(/\{[\s\S]*\}/);

  if (jsonMatch) {
    agentResults = JSON.parse(jsonMatch[0]);
  } else {
    // Fallback structure
    agentResults = {
      agent_id: systemContext.currentAgent || 'notion',
      task_id: $('Parse MCP Instructions').first().json.task_id,
      phase: systemContext.currentPhase,
      timestamp: new Date().toISOString(),
      execution_time_ms: Date.now() - new Date(systemContext.startTime).getTime(),
      results: {
        ideas_processed: [],
        summary: { total_processed: 0, successful: 0, failed: 0 }
      },
      status: {
        success: true,
        errors: [],
        next_phase: 'workflow_complete'
      }
    };
  }
} catch (error) {
  agentResults = {
    agent_id: systemContext.currentAgent || 'notion',
    task_id: 'error_task',
    phase: 'error',
    timestamp: new Date().toISOString(),
    error: error.message,
    status: { success: false, errors: [error.message] }
  };
}

// Update system context with results
systemContext.executionHistory.push({
  iteration: systemContext.iteration,
  timestamp: new Date().toISOString(),
  phase: 'agent_completed',
  agent: agentResults.agent_id,
  results_summary: agentResults.results?.summary || {},
  success: agentResults.status?.success || false
});

// Determine next phase
let nextPhase = 'workflow_complete';
if (agentResults.status?.next_phase === 'validation_required') {
  nextPhase = 'validation';
} else if (agentResults.results?.summary?.failed > 0) {
  nextPhase = 'error_review';
}

systemContext.currentPhase = nextPhase;
systemContext.iteration += 1;

// Calculate performance metrics
const totalExecutionTime = Date.now() - new Date(systemContext.startTime).getTime();
const performanceMetrics = {
  total_execution_time_ms: totalExecutionTime,
  ideas_processed: agentResults.results?.ideas_processed?.length || 0,
  success_rate: agentResults.results?.summary?.successful / (agentResults.results?.summary?.total_processed || 1),
  agent_performance: {
    agent_id: agentResults.agent_id,
    execution_time: agentResults.execution_time_ms,
    api_calls: agentResults.context_updates?.api_calls || 0
  }
};

return [{
  multiAgentResults: {
    workflow_complete: nextPhase === 'workflow_complete',
    agent_results: agentResults,
    system_context: systemContext,
    performance_metrics: performanceMetrics,
    next_phase: nextPhase,
    timestamp: new Date().toISOString()
  },
  summary: {
    total_ideas_processed: agentResults.results?.ideas_processed?.length || 0,
    projects_created: agentResults.results?.summary?.projects || 0,
    knowledge_entries: agentResults.results?.summary?.knowledge || 0,
    journal_entries: agentResults.results?.summary?.journal || 0,
    execution_time_ms: totalExecutionTime,
    success: agentResults.status?.success || false
  },
  rawAgentOutput: outputText || 'No output captured'
}];
